{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { size: A4 landscape; margin: 10mm 12mm 8mm 12mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 8.5pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 100%; margin: 0; padding: 0; }

  .hotel-logo { max-height: 52px; max-width: 95px; }
  .logo-box { display: inline-block; width: 44px; height: 44px; background: #1a1a2e; color: #fff; font-size: 15pt; font-weight: 700; text-align: center; line-height: 44px; border-radius: 5px; }
  .hotel-name { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 12pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 12px 0 14px; }

  .section-title { font-size: 7.5pt; font-weight: 700; color: #1a1a2e; text-transform: uppercase; letter-spacing: 0.6px; background: #f1f3f8; border-left: 3px solid #1a1a2e; border-bottom: 1px solid #d1d5db; padding: 5px 9px; margin-top: 14px; margin-bottom: 8px; }

  /* STATS */
  .stats-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
  .stats-table td { border: 1px solid #e5e7eb; padding: 5px 8px; text-align: center; }
  .s-label { font-size: 6.5pt; color: #9ca3af; display: block; text-transform: uppercase; letter-spacing: 0.4px; }
  .s-value { font-size: 11pt; font-weight: 700; color: #1a1a2e; display: block; margin-top: 2px; }
  .s-value.green { color: #15803d; }
  .s-value.red { color: #dc2626; }
  .s-value.amber { color: #d97706; }
  .s-value.blue { color: #1d4ed8; }

  /* PANELS */
  .panel-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
  .panel-table td { vertical-align: top; padding: 0 6px 0 0; }
  .panel-table td:last-child { padding-right: 0; }
  .panel { border: 1px solid #e5e7eb; padding: 8px; background: #fff; }
  .panel-title { font-size: 7.5pt; font-weight: 700; color: #1a1a2e; text-transform: uppercase; letter-spacing: 0.4px; margin-bottom: 6px; border-bottom: 2px solid #1a1a2e; padding-bottom: 4px; }
  .mini-table { width: 100%; border-collapse: collapse; font-size: 8pt; }
  .mini-table td { padding: 4px 4px; border-bottom: 1px solid #f1f5f9; }
  .mini-table tr:last-child td { border-bottom: none; }

  /* DATA TABLE */
  .data-table { width: 100%; border-collapse: collapse; font-size: 7.5pt; margin-bottom: 4px; }
  .data-table thead tr { background: #f1f3f8; color: #1a1a2e; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th { padding: 5px 5px; text-align: left; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.3px; white-space: nowrap; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th.num { text-align: right; }
  .data-table thead th.ctr { text-align: center; }
  .data-table tbody tr:nth-child(even) { background: #f9fafb; }
  .data-table tbody td { padding: 5px 5px; border-bottom: 1px solid #f1f5f9; color: #374151; vertical-align: middle; }
  .data-table tbody td.num { text-align: right; font-variant-numeric: tabular-nums; }
  .data-table tbody td.ctr { text-align: center; }
  .data-table tfoot tr { border-top: 2px solid #1a1a2e; background: #f1f3f8; color: #1a1a2e; }
  .data-table tfoot td { padding: 6px 5px; font-weight: 700; color: #1a1a2e; font-size: 8pt; }
  .data-table tfoot td.num { text-align: right; }

  /* BADGES */
  .badge { display: inline-block; padding: 1px 6px; border-radius: 8px; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; white-space: nowrap; }
  .badge-room-revenue { background: #dbeafe; color: #1d4ed8; }
  .badge-pos-revenue  { background: #ede9fe; color: #6d28d9; }
  .badge-other        { background: #f3f4f6; color: #4b5563; }
  .badge-payment      { background: #dcfce7; color: #166534; }
  .badge-paid         { background: #dcfce7; color: #166534; }
  .badge-unpaid       { background: #fee2e2; color: #b91c1c; }
  .badge-overdue      { background: #fee2e2; color: #b91c1c; }
  .badge-part         { background: #fef3c7; color: #b45309; }
  .badge-return       { background: #f3f4f6; color: #4b5563; }
  .ref { font-family: monospace; background: #f3f4f6; color: #374151; padding: 1px 4px; border-radius: 3px; font-size: 7pt; white-space: nowrap; }

  /* FOOTER */
  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 14px 0 8px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 14px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Night Audit Summary</div>
        <div class="doc-subtitle">Daily revenue, payments, room movement, occupancy, exceptions and audit summary.</div>
        <div class="doc-ref">
          <strong>Audit Date:</strong> {{ summary.audit_date or filters.audit_date }}<br>
          <strong>Generated:</strong> {{ generated_at }}<br>
          <strong>Prepared By:</strong> {{ prepared_by }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- REVENUE SUMMARY -->
  <div class="section-title">Revenue &amp; Payment Summary</div>
  <table class="stats-table" cellpadding="0" cellspacing="0">
    <tr>
      <td><span class="s-label">Total Revenue</span><span class="s-value green" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.total_revenue | float) }}</span></td>
      <td><span class="s-label">Room Revenue</span><span class="s-value" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.room_revenue | float) }}</span></td>
      <td><span class="s-label">POS Revenue</span><span class="s-value" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.pos_revenue | float) }}</span></td>
      <td><span class="s-label">Other Revenue</span><span class="s-value" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.other_revenue | float) }}</span></td>
      <td><span class="s-label">Amount Paid (Invoices)</span><span class="s-value green" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.total_paid | float) }}</span></td>
      <td><span class="s-label">Outstanding</span><span class="s-value red" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.total_outstanding | float) }}</span></td>
      <td><span class="s-label">Discounts Given</span><span class="s-value amber" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.total_discount | float) }}</span></td>
      <td><span class="s-label">Invoice Count</span><span class="s-value">{{ summary.transaction_count or 0 }}</span></td>
      <td><span class="s-label">Payment Entries</span><span class="s-value green" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.pe_total | float) }}</span></td>
      <td><span class="s-label">Exceptions</span><span class="s-value red">{{ summary.exceptions_count or 0 }}</span></td>
    </tr>
  </table>

  <!-- OCCUPANCY SUMMARY -->
  <div class="section-title">Occupancy Summary</div>
  <table class="stats-table" cellpadding="0" cellspacing="0">
    <tr>
      <td><span class="s-label">Total Rooms</span><span class="s-value">{{ summary.total_rooms or 0 }}</span></td>
      <td><span class="s-label">Occupied</span><span class="s-value green">{{ summary.occupied_rooms or 0 }}</span></td>
      <td><span class="s-label">Vacant</span><span class="s-value blue">{{ summary.vacant_rooms or 0 }}</span></td>
      <td><span class="s-label">Occupancy %</span><span class="s-value">{{ summary.occupancy_percent or 0 }}%</span></td>
      <td><span class="s-label">Arrivals</span><span class="s-value">{{ summary.arrivals or 0 }}</span></td>
      <td><span class="s-label">Departures</span><span class="s-value">{{ summary.departures or 0 }}</span></td>
      <td><span class="s-label">Stayovers</span><span class="s-value">{{ summary.stayovers or 0 }}</span></td>
      <td><span class="s-label">Credit Notes</span><span class="s-value red">{{ summary.credit_notes_count or 0 }}</span></td>
      <td><span class="s-label">Credit Notes Amount</span><span class="s-value red" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.credit_notes_amount | float) }}</span></td>
    </tr>
  </table>

  <!-- REVENUE & PAYMENT BREAKDOWN -->
  <div class="section-title">Breakdowns</div>
  <table class="panel-table" cellpadding="0" cellspacing="0">
    <tr>
      <td width="50%">
        <div class="panel">
          <div class="panel-title">Revenue Breakdown</div>
          <table class="mini-table" cellpadding="0" cellspacing="0">
            {% for item in revenue_breakdown %}
            <tr>
              <td>{{ item.type }}</td>
              <td style="text-align:right;font-weight:700;">&#x20a6;{{ "{:,.2f}".format(item.amount | float) }}</td>
            </tr>
            {% else %}
            <tr><td colspan="2" style="color:#9ca3af;font-style:italic;padding:8px 0;">No revenue breakdown found.</td></tr>
            {% endfor %}
          </table>
        </div>
      </td>
      <td width="50%" style="padding-left:6px;padding-right:0;">
        <div class="panel">
          <div class="panel-title">Payment Breakdown</div>
          <table class="mini-table" cellpadding="0" cellspacing="0">
            {% for item in payment_breakdown %}
            <tr>
              <td>{{ item.mode }}</td>
              <td style="text-align:right;font-weight:700;">&#x20a6;{{ "{:,.2f}".format(item.amount | float) }}</td>
            </tr>
            {% else %}
            <tr><td colspan="2" style="color:#9ca3af;font-style:italic;padding:8px 0;">No payment breakdown found.</td></tr>
            {% endfor %}
          </table>
        </div>
      </td>
    </tr>
  </table>

  <!-- EXCEPTIONS -->
  <div class="section-title">Audit Exceptions &mdash; {{ exceptions | length }} item(s)</div>
  {% if exceptions %}
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>Type</th><th>Reference</th><th>Description</th>
        <th class="num">Exception Amount</th><th class="num">Amount To Be Paid</th><th>Status</th>
      </tr>
    </thead>
    <tbody>
      {% for item in exceptions %}
      <tr>
        <td style="font-weight:700;">{{ item.type or '&mdash;' }}</td>
        <td><span class="ref">{{ item.reference or '&mdash;' }}</span></td>
        <td style="color:#6b7280;">{{ item.description or '&mdash;' }}</td>
        <td class="num" style="color:#dc2626;font-weight:700;">&#x20a6;{{ "{:,.2f}".format(item.exception_amount | float) }}</td>
        <td class="num" style="color:#dc2626;font-weight:700;">&#x20a6;{{ "{:,.2f}".format(item.amount_to_be_paid | float) }}</td>
        <td>
          {% set s = item.status or '' %}
          {% if s == 'Paid' %}<span class="badge badge-paid">Paid</span>
          {% elif s == 'Unpaid' %}<span class="badge badge-unpaid">Unpaid</span>
          {% elif s == 'Overdue' %}<span class="badge badge-overdue">Overdue</span>
          {% elif s == 'Part Payment' %}<span class="badge badge-part">Part Payment</span>
          {% else %}<span class="badge badge-return">{{ s or 'Review' }}</span>{% endif %}
        </td>
      </tr>
      {% endfor %}
    </tbody>
  </table>
  {% else %}
  <p style="padding:10px;color:#9ca3af;font-size:8pt;border:1px dashed #e5e7eb;">No audit exceptions found.</p>
  {% endif %}

  <!-- TRANSACTIONS -->
  <div class="section-title">Detailed Transactions &mdash; {{ rows | length }} record(s)</div>
  {% if rows %}
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th class="ctr">#</th><th>Type</th><th>Reference</th><th>Guest</th>
        <th>Room</th><th>Reservation</th><th>POS Profile</th><th>Payment Mode</th>
        <th class="num">Gross</th><th class="num">Tax</th><th class="num">Discount</th>
        <th class="num">Paid</th><th class="num">Outstanding</th><th>Status</th>
      </tr>
    </thead>
    <tbody>
      {% for row in rows %}
      <tr>
        <td class="ctr" style="color:#9ca3af;">{{ loop.index }}</td>
        <td>
          {% set t = row.transaction_type or '' %}
          {% if t == 'Room Revenue' %}<span class="badge badge-room-revenue">Room</span>
          {% elif t == 'POS Revenue' %}<span class="badge badge-pos-revenue">POS</span>
          {% elif t == 'Payment' %}<span class="badge badge-payment">Payment</span>
          {% else %}<span class="badge badge-other">{{ t or '&mdash;' }}</span>{% endif %}
        </td>
        <td><span class="ref">{{ row.reference or '&mdash;' }}</span></td>
        <td style="font-weight:600;">{{ row.guest or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ row.room or '&mdash;' }}</td>
        <td style="font-size:7pt;color:#6b7280;">{{ row.reservation or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ row.pos_profile or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ row.payment_mode or '&mdash;' }}</td>
        <td class="num" style="font-weight:600;">&#x20a6;{{ "{:,.0f}".format(row.gross_amount | float) }}</td>
        <td class="num" style="color:#6b7280;">&#x20a6;{{ "{:,.0f}".format(row.tax | float) }}</td>
        <td class="num" style="color:#d97706;">&#x20a6;{{ "{:,.0f}".format(row.discount | float) }}</td>
        <td class="num" style="color:#15803d;font-weight:600;">&#x20a6;{{ "{:,.0f}".format(row.paid_amount | float) }}</td>
        <td class="num {% if row.outstanding_amount | float > 0 %}style="color:#dc2626;font-weight:700;"{% endif %}">
          &#x20a6;{{ "{:,.0f}".format(row.outstanding_amount | float) }}
        </td>
        <td>
          {% set s = row.status or '' %}
          {% if s == 'Paid' %}<span class="badge badge-paid">Paid</span>
          {% elif s == 'Unpaid' %}<span class="badge badge-unpaid">Unpaid</span>
          {% elif s == 'Overdue' %}<span class="badge badge-overdue">Overdue</span>
          {% elif s == 'Part Payment' %}<span class="badge badge-part">Part</span>
          {% else %}<span class="badge badge-return">{{ s or '&mdash;' }}</span>{% endif %}
        </td>
      </tr>
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="8" style="text-align:right;text-transform:uppercase;letter-spacing:0.5px;">Total</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(totals.gross_amount | float) }}</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(totals.tax | float) }}</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(totals.discount | float) }}</td>
        <td class="num" style="color:#86efac;">&#x20a6;{{ "{:,.0f}".format(totals.paid_amount | float) }}</td>
        <td class="num" style="color:#fca5a5;">&#x20a6;{{ "{:,.0f}".format(totals.outstanding_amount | float) }}</td>
        <td></td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:16px;text-align:center;color:#9ca3af;font-size:8.5pt;border:1px dashed #e5e7eb;">No night audit transactions found.</p>
  {% endif %}

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This report is generated by the {{ company }} Property Management System.<br>
          Night audit note: Review revenue, payments, exceptions, occupancy and unsettled balances before closing the business day.<br>
          <strong style="color:#374151;">Audit Date: {{ summary.audit_date or filters.audit_date }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
